"use client";

import { useState, useEffect } from "react";
import { X, Save, AlertCircle } from "lucide-react";
import { getFirebaseDb } from "@/lib/firebase";
import { doc, setDoc, addDoc, collection, serverTimestamp } from "firebase/firestore";

interface ParticipanteModalProps {
  isOpen: boolean;
  onClose: () => void;
  itemToEdit?: any | null;
  onSaved: () => void;
}

export default function ParticipanteModal({ isOpen, onClose, itemToEdit, onSaved }: ParticipanteModalProps) {
  const [formData, setFormData] = useState<any>({
    nome: '',
    email: '',
    telefone: '',
    funcao: '',
    tamanho: 'M'
  });
  const [saving, setSaving] = useState(false);
  const [error, setError] = useState('');

  useEffect(() => {
    if (itemToEdit) {
      setFormData(itemToEdit);
    } else {
      setFormData({
        nome: '',
        email: '',
        telefone: '',
        funcao: '',
        tamanho: 'M'
      });
    }
    setError('');
  }, [itemToEdit, isOpen]);

  if (!isOpen) return null;

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
    const { name, value } = e.target;
    setFormData((prev: any) => ({ ...prev, [name]: value }));
  };

  const handleSave = async () => {
    if (!formData.nome) {
       setError("Nome ├® obrigat├│rio.");
       return;
    }
    setSaving(true);
    try {
      const db = getFirebaseDb();
      const payload = { ...formData, updatedAt: serverTimestamp() };

      if (itemToEdit?.id) {
        await setDoc(doc(db, "participantes", itemToEdit.id), payload, { merge: true });
      } else {
        await addDoc(collection(db, "participantes"), { ...payload, createdAt: serverTimestamp() });
      }
      onSaved();
      onClose();
    } catch (err: any) {
      setError(err.message || 'Erro ao salvar o participante.');
    } finally {
      setSaving(false);
    }
  };

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
      <div className="absolute inset-0 bg-slate-950/60 backdrop-blur-md animate-in fade-in duration-700 ease-[cubic-bezier(0.23,1,0.32,1)]" onClick={onClose} />
      <div className="relative bg-surface w-full max-w-lg rounded-[32px] shadow-[0_40px_100px_-12px_rgba(0,0,0,0.5),0_0_0_1px_rgba(255,255,255,0.1)] flex flex-col overflow-hidden animate-in fade-in zoom-in-95 slide-in-from-bottom-10 duration-700 ease-[cubic-bezier(0.23,1,0.32,1)] border border-border">
        <div className="flex items-center justify-between p-8 border-b border-border bg-surface">
          <h2 className="text-2xl font-black text-text tracking-tight">
            {itemToEdit ? "Editar Participante" : "Novo Participante"}
          </h2>
          <button onClick={onClose} className="p-2 hover:bg-muted/10 rounded-full transition-colors text-muted">
            <X className="w-6 h-6" />
          </button>
        </div>

        <div className="p-8 space-y-6 overflow-y-auto max-h-[70vh] bg-bg/30">
          {error && (
            <div className="bg-red/10 text-red p-4 rounded-2xl flex items-center gap-3 text-sm font-bold border border-red/20">
              <AlertCircle className="w-5 h-5"/> {error}
            </div>
          )}

          <div>
             <label className="block text-[10px] font-black text-muted uppercase tracking-widest mb-2 ml-1">Nome Completo *</label>
             <input type="text" name="nome" value={formData.nome} onChange={handleChange} className="w-full bg-surface text-text text-base px-5 py-4 rounded-2xl border border-border focus:border-accent outline-none font-bold transition-all" placeholder="Nome do integrante..." />
          </div>

          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
             <div>
                <label className="block text-[10px] font-black text-muted uppercase tracking-widest mb-2 ml-1">E-mail</label>
                <input type="email" name="email" value={formData.email} onChange={handleChange} className="w-full bg-surface text-text text-sm px-5 py-3.5 rounded-2xl border border-border focus:border-accent outline-none font-medium transition-all" placeholder="email@exemplo.com" />
             </div>
             <div>
                <label className="block text-[10px] font-black text-muted uppercase tracking-widest mb-2 ml-1">Telefone</label>
                <input type="text" name="telefone" value={formData.telefone} onChange={handleChange} className="w-full bg-surface text-text text-sm px-5 py-3.5 rounded-2xl border border-border focus:border-accent outline-none font-medium transition-all" placeholder="(00) 00000-0000" />
             </div>
          </div>

          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
             <div>
                <label className="block text-[10px] font-black text-muted uppercase tracking-widest mb-2 ml-1">Fun├º├úo Padr├úo</label>
                <input type="text" name="funcao" value={formData.funcao} onChange={handleChange} placeholder="Ex: Staff, Fot├│grafo" className="w-full bg-surface text-text text-sm px-5 py-3.5 rounded-2xl border border-border focus:border-accent outline-none font-medium transition-all" />
             </div>
             <div>
                <label className="block text-[10px] font-black text-muted uppercase tracking-widest mb-2 ml-1">Tam. Camisa</label>
                <select name="tamanho" value={formData.tamanho} onChange={handleChange} className="w-full bg-surface text-text text-sm font-bold px-5 py-3.5 rounded-2xl border border-border focus:border-accent outline-none transition-all cursor-pointer">
                   <option value="P">P</option>
                   <option value="M">M</option>
                   <option value="G">G</option>
                   <option value="GG">GG</option>
                   <option value="XG">XG</option>
                   <option value="Baby Look P">Baby Look P</option>
                   <option value="Baby Look M">Baby Look M</option>
                   <option value="Baby Look G">Baby Look G</option>
                   <option value="Baby Look GG">Baby Look GG</option>
                </select>
             </div>
          </div>
        </div>

        <div className="p-6 border-t border-border bg-surface flex justify-end gap-4 flex-shrink-0">
          <button onClick={onClose} className="px-6 py-3 text-sm font-bold text-muted hover:bg-muted/10 rounded-2xl transition-all">Cancelar</button>
          <button onClick={handleSave} disabled={saving} className="flex items-center gap-2 px-10 py-3 bg-accent hover:bg-accent-hover text-white text-sm font-black rounded-2xl shadow-lg shadow-accent/20 transition-all disabled:opacity-50">
            {saving ? <Loader2 className="w-4 h-4 animate-spin" /> : <Save className="w-4 h-4"/>}
            {saving ? 'Salvando...' : 'Salvar Participante'}
          </button>
        </div>
      </div>
    </div>
  );
}

import { Loader2 } from "lucide-react";

"use client";

import { useEvents } from "@/store/useEvents";
import { Filter, Calendar as CalendarIcon, List, Clock, Search, ChevronLeft, ChevronRight, LayoutDashboard, Bell, CheckCircle2, MapPin, Users, Tag, Monitor, CalendarDays, X } from "lucide-react";
import { format, addMonths, subMonths, isSameDay } from "date-fns";
import { ptBR } from "date-fns/locale";
import { useState, useMemo } from "react";
import { cn } from "../lib/utils";
import { parseEventStringDate } from "@/lib/dateUtils";

export default function SidebarFilters() {
  const { 
    selectedStatus, toggleStatus,
    selectedTipos, toggleTipo,
    selectedResps, toggleResp,
    selectedFormatos, toggleFormato,
    filterStartDate, setFilterStartDate,
    filterEndDate, setFilterEndDate,
    events 
  } = useEvents();

  const [currentMonth, setCurrentMonth] = useState(new Date());

  // Get all unique responsibles from events
  const allResps = useMemo(() => {
    const resps = new Set<string>();
    events.forEach(e => {
      if (e.responsavel) {
        e.responsavel.split(',').forEach(r => resps.add(r.trim()));
      }
    });
    return Array.from(resps).sort();
  }, [events]);

  const eventDatesSet = useMemo(() => {
    const set = new Set();
    events.forEach(e => {
      const d = parseEventStringDate(e.data_ini);
      if (d) set.add(format(d, "yyyy-MM-dd"));
    });
    return set;
  }, [events]);

  const upcomingEvents = useMemo(() => {
    return [...events]
      .filter(e => {
        const d = parseEventStringDate(e.data_ini);
        return d && d >= new Date();
      })
      .sort((a, b) => {
        const da = parseEventStringDate(a.data_ini);
        const db = parseEventStringDate(b.data_ini);
        return (da?.getTime() || 0) - (db?.getTime() || 0);
      })
      .slice(0, 4); // show up to 4
  }, [events]);

  const renderMiniCalendar = () => {
    const days = ["D", "S", "T", "Q", "Q", "S", "S"];
    const start = new Date(currentMonth.getFullYear(), currentMonth.getMonth(), 1);
    const end = new Date(currentMonth.getFullYear(), currentMonth.getMonth() + 1, 0);
    const startDay = start.getDay();
    const dateArr = [];
    for (let i = 0; i < startDay; i++) dateArr.push(null);
    for (let i = 1; i <= end.getDate(); i++) dateArr.push(new Date(currentMonth.getFullYear(), currentMonth.getMonth(), i));

    return (
      <div className="bg-surface/40 backdrop-blur-xl rounded-3xl p-6 border border-white/5 shadow-[0_8px_30px_rgb(0,0,0,0.04)] transition-all">
        <div className="flex items-center justify-between mb-5">
          <h4 className="text-xs font-black text-text uppercase tracking-widest">{format(currentMonth, "MMMM yyyy", { locale: ptBR })}</h4>
          <div className="flex items-center gap-1 bg-surface border border-white/5 rounded-xl p-0.5 shadow-inner">
            <button aria-label="M├¬s anterior" onClick={() => setCurrentMonth(subMonths(currentMonth, 1))} className="p-1.5 hover:bg-white/5 rounded-lg transition-all text-muted hover:text-text active:scale-95"><ChevronLeft className="w-3.5 h-3.5" /></button>
            <div className="w-[1px] h-3 bg-white/10 mx-0.5" />
            <button aria-label="Pr├│ximo m├¬s" onClick={() => setCurrentMonth(addMonths(currentMonth, 1))} className="p-1.5 hover:bg-white/5 rounded-lg transition-all text-muted hover:text-text active:scale-95"><ChevronRight className="w-3.5 h-3.5" /></button>
          </div>
        </div>
        <div className="grid grid-cols-7 gap-y-3 gap-x-1 text-center">
          {days.map((d, i) => <div key={`${d}-${i}`} className="text-[10px] font-black text-muted/40 uppercase tracking-widest mb-1">{d}</div>)}
          {dateArr.map((date, i) => {
            if (!date) return <div key={i} />;
            const dateStr = format(date, "yyyy-MM-dd");
            const hasEvent = eventDatesSet.has(dateStr);
            const isSelected = filterStartDate === dateStr && filterEndDate === dateStr;
            const isToday = isSameDay(date, new Date());

            const handleDateClick = () => {
              if (isSelected) {
                setFilterStartDate('');
                setFilterEndDate('');
              } else {
                setFilterStartDate(dateStr);
                setFilterEndDate(dateStr);
              }
            };

            return (
              <div key={i} onClick={handleDateClick} className="relative flex items-center justify-center py-0.5 cursor-pointer group">
                <span className={cn(
                  "text-xs font-bold w-8 h-8 flex items-center justify-center rounded-xl transition-all duration-300",
                  isSelected ? "bg-accent text-white shadow-lg shadow-accent/25 scale-110 font-black" : 
                  isToday ? "bg-surface text-accent ring-1 ring-accent/30 font-black" : "text-text group-hover:bg-surface group-hover:scale-110",
                  hasEvent && !isSelected && !isToday && "font-black"
                )}>
                  {date.getDate()}
                </span>
                {hasEvent && !isSelected && (
                  <div className="absolute bottom-0 left-1/2 -translate-x-1/2 w-1 h-1 bg-accent rounded-full shadow-[0_0_4px_var(--accent)]" />
                )}
              </div>
            );
          })}
        </div>
      </div>
    );
  };

  const FilterSection = ({ title, icon, children }: { title: string, icon: any, children: React.ReactNode }) => (
    <div className="space-y-3 w-full">
       <div className="flex items-center gap-2 px-1">
          {icon}
          <h3 className="text-[10px] font-black text-muted uppercase tracking-widest">{title}</h3>
       </div>
       <div className="flex flex-col gap-2 w-full">
          {children}
       </div>
    </div>
  );

  const MultiSelect = ({ options, selected, toggle, placeholder }: { options: string[], selected: string[], toggle: (val: string) => void, placeholder: string }) => {
    return (
      <div className="flex flex-col gap-2 w-full">
         <select 
           className="w-full bg-surface border border-border rounded-xl px-3 py-2 text-xs font-bold text-text focus:outline-none focus:border-accent focus:ring-1 focus:ring-accent transition-all appearance-none cursor-pointer"
           value=""
           onChange={(e) => {
             if(e.target.value) toggle(e.target.value);
           }}
         >
           <option value="" disabled className="text-muted">{placeholder}</option>
           {options.map(o => (
             <option key={o} value={o}>{o}</option>
           ))}
         </select>
         {selected.length > 0 && (
           <div className="flex flex-wrap gap-1.5 mt-1">
              {selected.map(s => (
                 <span key={s} className="bg-accent/10 text-accent border border-accent/20 px-2 py-1.5 rounded-lg text-[10px] font-bold tracking-wider flex items-center gap-1.5 group transition-colors hover:bg-accent hover:text-white">
                   {s}
                   <button onClick={(e) => { e.stopPropagation(); toggle(s); }} className="opacity-70 group-hover:opacity-100 transition-opacity"><X className="w-3.5 h-3.5"/></button>
                 </span>
              ))}
           </div>
         )}
      </div>
    );
  };

  const FilterSwitch = ({ label, isActive, onClick }: { label: string, isActive: boolean, onClick: () => void }) => (
    <div onClick={onClick} className="flex items-center justify-between w-full p-3 bg-surface border border-border rounded-xl cursor-pointer hover:border-text/30 transition-all group">
      <span className="text-[11px] font-bold text-text uppercase tracking-wider">{label}</span>
      <div className={cn(
        "relative inline-flex h-5 w-9 items-center rounded-full transition-colors duration-300 shrink-0",
        isActive ? "bg-accent" : "bg-muted/30"
      )}>
        <span className={cn(
          "inline-block h-3.5 w-3.5 transform rounded-full bg-white transition-transform duration-300",
          isActive ? "translate-x-[18px] shadow-md" : "translate-x-1"
        )} />
      </div>
    </div>
  );

  return (
    <aside className="w-full lg:w-80 flex-shrink-0 flex flex-col gap-6 p-5 lg:p-6 overflow-y-auto h-full custom-scrollbar bg-surface/50 border-r border-border transition-all duration-700 ease-[cubic-bezier(0.23,1,0.32,1)]">

      {/* 1. Header */}
      <div className="flex items-center gap-3 group">
         <div className="w-8 h-8 rounded-lg bg-accent/10 flex items-center justify-center border border-accent/20 group-hover:scale-105 transition-transform">
           <Filter className="w-4 h-4 text-accent"/>
         </div>
         <h2 className="text-xs font-black text-text uppercase tracking-widest">Filtros de Busca</h2>
      </div>

      {/* 2. Mini Calendar */}
      {renderMiniCalendar()}

      {/* 3. Detailed Filters */}
